import{_ as o,o as a,c as t,a2 as i}from"./chunks/framework.C69UpXSI.js";const m=JSON.parse('{"title":"Economy Mode","description":"","frontmatter":{},"headers":[],"relativePath":"it/configurazione/economy.md","filePath":"it/configurazione/economy.md"}'),n={name:"it/configurazione/economy.md"};function r(l,e,s,c,d,u){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="economy-mode" tabindex="-1">Economy Mode <a class="header-anchor" href="#economy-mode" aria-label="Permalink to &quot;Economy Mode&quot;">​</a></h1><p>L&#39;<strong>Economy Mode</strong> di TurboDev riduce il consumo di token istruendo l&#39;AI a produrre output conciso. Quando attiva, il system prompt include una direttiva che fa sì che l&#39;LLM elimini le parole di riempimento, usi frammenti di frase e mantenga il codice esatto — stessa accuratezza tecnica, ~50-70% token in output in meno, risparmio diretto sui costi.</p><p>Ispirato a <a href="https://github.com/JuliusBrussee/caveman" target="_blank" rel="noreferrer">Caveman</a>, implementato nativamente — nessuna skill esterna o dipendenza.</p><h2 id="come-funziona" tabindex="-1">Come Funziona <a class="header-anchor" href="#come-funziona" aria-label="Permalink to &quot;Come Funziona&quot;">​</a></h2><ol><li>Attivi un livello con <code>/economy eco</code> o <code>/economy ultra</code></li><li>TurboDev aggiunge una direttiva di concisione al system prompt</li><li>L&#39;LLM produce risposte più brevi — frammenti invece di paragrafi</li><li>Codice, comandi, percorsi file e messaggi di errore restano <strong>byte-exact</strong></li><li>Il livello è persistito in <code>~/.turbodevrc</code> e sopravvive ai restart</li></ol><p>La direttiva economy costa ~60 token (trascurabile rispetto al risparmio in output).</p><h2 id="livelli" tabindex="-1">Livelli <a class="header-anchor" href="#livelli" aria-label="Permalink to &quot;Livelli&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Livello</th><th>Descrizione</th><th>Risparmio Output Stimato</th><th>Badge</th></tr></thead><tbody><tr><td><code>off</code> (default)</td><td>Output normale — frasi complete, spiegazioni</td><td>0%</td><td>—</td></tr><tr><td><code>eco</code></td><td>Diretto e conciso. Niente filler, niente convenevoli.</td><td>~50%</td><td><code>ECO</code> (giallo)</td></tr><tr><td><code>ultra</code></td><td>Frammenti telegrafici. Nessuna spiegazione se non richiesta.</td><td>~70%</td><td><code>ULTRA</code> (rosso)</td></tr></tbody></table><h2 id="comandi" tabindex="-1">Comandi <a class="header-anchor" href="#comandi" aria-label="Permalink to &quot;Comandi&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>/economy</code></td><td>Mostra il livello corrente e l&#39;usage</td></tr><tr><td><code>/economy eco</code></td><td>Attiva livello eco (alias: <code>/economy on</code>)</td></tr><tr><td><code>/economy ultra</code></td><td>Attiva livello ultra</td></tr><tr><td><code>/economy off</code></td><td>Disattiva economy mode</td></tr></tbody></table><h2 id="prima-dopo" tabindex="-1">Prima / Dopo <a class="header-anchor" href="#prima-dopo" aria-label="Permalink to &quot;Prima / Dopo&quot;">​</a></h2><h3 id="normale-69-token" tabindex="-1">Normale (69 token) <a class="header-anchor" href="#normale-69-token" aria-label="Permalink to &quot;Normale (69 token)&quot;">​</a></h3><blockquote><p>&quot;The reason your React component is re-rendering is likely because you&#39;re creating a new object reference on each render cycle. I&#39;d recommend using useMemo to memoize the object.&quot;</p></blockquote><h3 id="eco-35-token" tabindex="-1">Eco (~35 token) <a class="header-anchor" href="#eco-35-token" aria-label="Permalink to &quot;Eco (~35 token)&quot;">​</a></h3><blockquote><p>&quot;Component re-renders because inline object prop creates new ref each cycle. Wrap in <code>useMemo</code>.&quot;</p></blockquote><h3 id="ultra-19-token" tabindex="-1">Ultra (~19 token) <a class="header-anchor" href="#ultra-19-token" aria-label="Permalink to &quot;Ultra (~19 token)&quot;">​</a></h3><blockquote><p>&quot;Inline object prop = new ref each render = re-render. Use <code>useMemo</code>.&quot;</p></blockquote><p>Stessa soluzione. Stessa accuratezza. Meno token.</p><h2 id="cosa-resta-esatto" tabindex="-1">Cosa Resta Esatto <a class="header-anchor" href="#cosa-resta-esatto" aria-label="Permalink to &quot;Cosa Resta Esatto&quot;">​</a></h2><p>Economy mode comprime lo <strong>stile del testo</strong>, non il <strong>contenuto tecnico</strong>:</p><ul><li>✅ Blocchi di codice — byte-exact</li><li>✅ Comandi e flag CLI — exact</li><li>✅ Percorsi file — exact</li><li>✅ Messaggi di errore — exact</li><li>✅ Lingua dell&#39;utente — preservata (input italiano → output italiano conciso)</li><li>❌ Parole di riempimento (&quot;let me...&quot;, &quot;sure!&quot;, &quot;I&#39;ll now...&quot;) — eliminate</li><li>❌ Ripetere la domanda — eliminato</li><li>❌ Transizioni e convenevoli — eliminati</li></ul><h2 id="persistenza" tabindex="-1">Persistenza <a class="header-anchor" href="#persistenza" aria-label="Permalink to &quot;Persistenza&quot;">​</a></h2><p>Il livello è salvato in <code>~/.turbodevrc</code>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;economy&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;level&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;eco&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>All&#39;avvio, TurboDev carica il livello salvato e attiva economy mode automaticamente. Cambialo in qualsiasi momento con <code>/economy</code>.</p><h2 id="statusbar" tabindex="-1">StatusBar <a class="header-anchor" href="#statusbar" aria-label="Permalink to &quot;StatusBar&quot;">​</a></h2><p>Quando economy mode è attivo, la StatusBar mostra un badge colorato:</p><ul><li><code>ECO</code> (giallo) — livello eco attivo</li><li><code>ULTRA</code> (rosso) — livello ultra attivo</li></ul><p>Il badge si trova accanto all&#39;indicatore di costo, così puoi vedere risparmio e spesa a colpo d&#39;occhio.</p><h2 id="quando-usarlo" tabindex="-1">Quando Usarlo <a class="header-anchor" href="#quando-usarlo" aria-label="Permalink to &quot;Quando Usarlo&quot;">​</a></h2><ul><li><strong><code>eco</code></strong> — lavoro quotidiano. Risposte dirette, ancora leggibili. Miglior equilibrio tra chiarezza e risparmio.</li><li><strong><code>ultra</code></strong> — sessioni power. Massima densità, minimo testo. Sai cosa stai facendo e vuoi solo la risposta.</li><li><strong><code>off</code></strong> — apprendimento/esplorazione. Quando vuoi spiegazioni complete e contesto.</li></ul><h2 id="ispirazione" tabindex="-1">Ispirazione <a class="header-anchor" href="#ispirazione" aria-label="Permalink to &quot;Ispirazione&quot;">​</a></h2><p>Economy Mode è ispirato a <a href="https://github.com/JuliusBrussee/caveman" target="_blank" rel="noreferrer">Caveman</a> di Julius Brussee — una skill per Claude Code che ha dimostrato che una semplice istruzione nel prompt può tagliare il 65% dei token in output senza perdere accuratezza tecnica. TurboDev implementa il suo prompt di concisione nativo; non installa o bundle la skill Caveman.</p>`,33)])])}const h=o(n,[["render",r]]);export{m as __pageData,h as default};
